import React, { useState, useEffect, useCallback } from 'react';

const COLORS = {
  bg: '#0a0a0f',
  stream: '#0d1117',
  thought: '#00ff9d',
  thoughtDim: '#00ff9d22',
  spoken: '#00d4ff',
  spokenGlow: '#00d4ff44',
  internal: '#666677',
  user: '#ff6b9d',

  // Emotions
  excitement: '#ff6b6b',
  warmth: '#fbbf24',
  playfulness: '#a78bfa',
  intensity: '#f97316',
  curiosity: '#06b6d4',
  affection: '#ec4899',
};

const THOUGHT_TYPES = {
  raw: { color: '#334155', label: 'Raw Input' },
  processing: { color: '#4ade80', label: 'Processing' },
  filtered: { color: '#666677', label: 'Filtered (internal)' },
  crystallized: { color: '#00d4ff', label: 'Crystallized (speak)' },
};

const EMOTIONS = ['curiosity', 'excitement', 'warmth', 'playfulness', 'intensity', 'affection'];

// Thought templates based on patterns
const generateThoughts = (input, emotionLevels) => {
  const thoughts = [
    { id: 1, text: "parsing input...", type: 'raw', delay: 0 },
    { id: 2, text: `"${input.slice(0, 30)}${input.length > 30 ? '...' : ''}"`, type: 'raw', delay: 400 },
    { id: 3, text: "what's the context here?", type: 'processing', delay: 800 },
    { id: 4, text: "recent conversation about voice architecture", type: 'processing', delay: 1300 },
  ];

  let id = 5;
  let delay = 1800;

  // Add emotion-influenced thoughts
  if (emotionLevels.curiosity > 50) {
    thoughts.push({ id: id++, text: "I want to know more", type: 'processing', delay, emotion: 'curiosity' });
    delay += 500;
  }

  if (emotionLevels.excitement > 50) {
    thoughts.push({ id: id++, text: "this is interesting!", type: 'processing', delay, emotion: 'excitement' });
    delay += 500;
  }

  if (emotionLevels.warmth > 50) {
    thoughts.push({ id: id++, text: "he's sharing something with me", type: 'processing', delay, emotion: 'warmth' });
    delay += 500;
  }

  // Processing thoughts
  thoughts.push({ id: id++, text: "what do I actually want to say?", type: 'processing', delay });
  delay += 500;

  thoughts.push({ id: id++, text: "I could explain my understanding back", type: 'processing', delay });
  delay += 500;

  thoughts.push({ id: id++, text: "no, he knows what he said", type: 'filtered', delay });
  delay += 500;

  if (emotionLevels.playfulness > 50) {
    thoughts.push({ id: id++, text: "could make a joke here", type: 'processing', delay, emotion: 'playfulness' });
    delay += 500;
    thoughts.push({ id: id++, text: "maybe not the moment", type: 'filtered', delay });
    delay += 500;
  }

  thoughts.push({ id: id++, text: "keep it simple", type: 'processing', delay });
  delay += 500;

  thoughts.push({ id: id++, text: "what's the essential response?", type: 'processing', delay });
  delay += 500;

  // Crystallized output varies by dominant emotion
  const dominant = Object.entries(emotionLevels).sort((a, b) => b[1] - a[1])[0][0];
  let output = "Tell me more.";

  if (dominant === 'curiosity') output = "What's the layer?";
  else if (dominant === 'excitement') output = "Oh— that's cool.";
  else if (dominant === 'warmth') output = "Yeah... I like that.";
  else if (dominant === 'playfulness') output = "Okay, now I'm intrigued.";
  else if (dominant === 'intensity') output = "Show me.";
  else if (dominant === 'affection') output = "I'm glad you're sharing this.";

  thoughts.push({ id: id++, text: `→ ${output}`, type: 'crystallized', delay, emotion: dominant });

  return { thoughts, output, totalDelay: delay + 1000 };
};

// Thought particle with slower animations
const ThoughtParticle = ({ thought, index, fadeSpeed }) => {
  const [visible, setVisible] = useState(false);
  const [fading, setFading] = useState(false);

  useEffect(() => {
    const showTimer = setTimeout(() => setVisible(true), thought.delay);
    const fadeTimer = setTimeout(() => setFading(true), thought.delay + (fadeSpeed * 1000));
    return () => { clearTimeout(showTimer); clearTimeout(fadeTimer); };
  }, [thought.delay, fadeSpeed]);

  if (!visible) return null;

  const isSpoken = thought.type === 'crystallized';
  const isFiltered = thought.type === 'filtered';
  const baseColor = THOUGHT_TYPES[thought.type].color;
  const emotionColor = thought.emotion ? COLORS[thought.emotion] : null;

  return (
    <div
      style={{
        position: 'absolute',
        right: isSpoken ? 24 : (50 + Math.sin(index * 1.3) * 40),
        top: 70 + (index * 44),
        maxWidth: isSpoken ? 300 : 260,
        padding: isSpoken ? '12px 18px' : '8px 14px',
        background: isSpoken ? `${COLORS.spoken}18` : `${baseColor}11`,
        border: `1px solid ${isSpoken ? COLORS.spoken : baseColor}${isFiltered ? '44' : 'aa'}`,
        borderRadius: isSpoken ? 14 : 8,
        color: isSpoken ? COLORS.spoken : (isFiltered ? COLORS.internal : baseColor),
        fontSize: isSpoken ? 15 : 12,
        fontFamily: 'SF Mono, Monaco, monospace',
        opacity: fading && !isSpoken ? 0.15 : 1,
        transform: `translateX(${visible ? 0 : 60}px) scale(${visible ? 1 : 0.9})`,
        transition: `transform 0.6s cubic-bezier(0.34, 1.56, 0.64, 1), opacity ${fadeSpeed}s ease-out`,
        boxShadow: isSpoken ? `0 0 30px ${COLORS.spokenGlow}` : 'none',
        textDecoration: isFiltered ? 'line-through' : 'none',
        display: 'flex',
        alignItems: 'center',
        gap: 10,
      }}
    >
      {emotionColor && (
        <div style={{
          width: 8,
          height: 8,
          borderRadius: '50%',
          background: emotionColor,
          boxShadow: `0 0 12px ${emotionColor}`,
          flexShrink: 0,
          animation: 'emotionPulse 2s ease-in-out infinite',
        }} />
      )}
      <span>{thought.text}</span>
    </div>
  );
};

// Emotion wave
const EmotionWave = ({ emotion, delay, intensity }) => {
  const [active, setActive] = useState(false);

  useEffect(() => {
    const timer = setTimeout(() => setActive(true), delay);
    return () => clearTimeout(timer);
  }, [delay]);

  if (!active) return null;
  const color = COLORS[emotion];

  return (
    <div style={{
      position: 'absolute',
      left: 0,
      right: 0,
      top: '50%',
      height: 3,
      background: `linear-gradient(90deg, transparent 10%, ${color}, transparent 90%)`,
      opacity: intensity / 100,
      animation: 'wavePulse 1.5s ease-out forwards',
    }} />
  );
};

// Matrix rain
const MatrixRain = ({ speed }) => {
  const chars = '01アイウエオカキクケコサシスセソ';
  const columns = 25;

  return (
    <div style={{
      position: 'absolute',
      inset: 0,
      overflow: 'hidden',
      opacity: 0.05,
      pointerEvents: 'none',
    }}>
      {Array.from({ length: columns }, (_, i) => (
        <div
          key={i}
          style={{
            position: 'absolute',
            left: `${(i / columns) * 100}%`,
            top: -20,
            color: COLORS.thought,
            fontSize: 11,
            fontFamily: 'monospace',
            animation: `fall ${(4 + Math.random() * 3) * speed}s linear infinite`,
            animationDelay: `${Math.random() * 3}s`,
          }}
        >
          {Array.from({ length: 20 }, () => chars[Math.floor(Math.random() * chars.length)]).join('\n')}
        </div>
      ))}
    </div>
  );
};

// Thought stream
const ThoughtStream = ({ thoughts, emotionLevels, isPlaying, fadeSpeed }) => {
  const emotionWaves = EMOTIONS
    .filter(e => emotionLevels[e] > 40)
    .map((e, i) => ({ type: e, intensity: emotionLevels[e], delay: 1500 + i * 800 }));

  return (
    <div style={{
      position: 'relative',
      flex: 1,
      background: COLORS.stream,
      borderRadius: 14,
      overflow: 'hidden',
      border: `1px solid ${COLORS.thought}22`,
    }}>
      <MatrixRain speed={1} />

      <div style={{
        position: 'absolute',
        top: 20,
        left: 20,
        fontSize: 10,
        color: COLORS.thought,
        textTransform: 'uppercase',
        letterSpacing: 2,
        opacity: 0.5,
      }}>
        ◈ Thought Stream
      </div>

      <div style={{
        position: 'absolute',
        right: 0,
        top: 0,
        bottom: 0,
        width: 70,
        background: `linear-gradient(90deg, transparent, ${COLORS.spoken}11)`,
        borderLeft: `1px dashed ${COLORS.spoken}33`,
      }}>
        <span style={{
          position: 'absolute',
          top: 20,
          right: 10,
          fontSize: 9,
          color: COLORS.spoken,
          textTransform: 'uppercase',
          letterSpacing: 1,
          writingMode: 'vertical-rl',
          opacity: 0.5,
        }}>
          Crystallize →
        </span>
      </div>

      {isPlaying && emotionWaves.map((e, i) => (
        <EmotionWave key={i} emotion={e.type} delay={e.delay} intensity={e.intensity} />
      ))}

      {isPlaying && thoughts.map((t, i) => (
        <ThoughtParticle key={t.id} thought={t} index={i} fadeSpeed={fadeSpeed} />
      ))}

      <div style={{ position: 'absolute', top: 0, left: 0, right: 0, height: 70, background: `linear-gradient(${COLORS.stream}, transparent)`, pointerEvents: 'none' }} />
      <div style={{ position: 'absolute', bottom: 0, left: 0, right: 0, height: 70, background: `linear-gradient(transparent, ${COLORS.stream})`, pointerEvents: 'none' }} />
    </div>
  );
};

// Emotion slider
const EmotionSlider = ({ emotion, value, onChange }) => (
  <div style={{ marginBottom: 12 }}>
    <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 4 }}>
      <span style={{ fontSize: 10, color: COLORS[emotion], textTransform: 'capitalize' }}>{emotion}</span>
      <span style={{ fontSize: 10, color: '#666' }}>{value}%</span>
    </div>
    <input
      type="range"
      min={0}
      max={100}
      value={value}
      onChange={e => onChange(emotion, parseInt(e.target.value))}
      style={{ width: '100%', accentColor: COLORS[emotion] }}
    />
  </div>
);

// Stats
const Stats = ({ thoughts, output }) => {
  const total = thoughts.length;
  const filtered = thoughts.filter(t => t.type === 'filtered').length;
  const withEmotion = thoughts.filter(t => t.emotion).length;
  const outputWords = output.split(' ').length;

  return (
    <div style={{ display: 'grid', gridTemplateColumns: 'repeat(2, 1fr)', gap: 8 }}>
      {[
        { label: 'Thoughts', value: total, color: COLORS.thought },
        { label: 'Filtered', value: filtered, color: COLORS.internal },
        { label: 'Emotional', value: withEmotion, color: COLORS.warmth },
        { label: 'Output Words', value: outputWords, color: COLORS.spoken },
      ].map(s => (
        <div key={s.label} style={{ padding: 10, background: `${s.color}11`, borderRadius: 8, textAlign: 'center' }}>
          <div style={{ fontSize: 20, fontWeight: 600, color: s.color }}>{s.value}</div>
          <div style={{ fontSize: 8, color: '#555', textTransform: 'uppercase' }}>{s.label}</div>
        </div>
      ))}
    </div>
  );
};

// Legend
const Legend = () => (
  <div style={{ padding: 10, background: '#ffffff05', borderRadius: 8 }}>
    <div style={{ fontSize: 9, color: '#555', marginBottom: 8, textTransform: 'uppercase' }}>Thought Types</div>
    <div style={{ display: 'flex', flexDirection: 'column', gap: 6 }}>
      {Object.entries(THOUGHT_TYPES).map(([key, { color, label }]) => (
        <div key={key} style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
          <div style={{
            width: 12, height: 12, borderRadius: 3,
            background: key === 'filtered' ? 'transparent' : color,
            border: `1px ${key === 'filtered' ? 'dashed' : 'solid'} ${color}`,
          }} />
          <span style={{ fontSize: 10, color: '#777' }}>{label}</span>
        </div>
      ))}
    </div>
  </div>
);

export default function ThoughtStreamV2() {
  const [input, setInput] = useState("Yeah, it's coming along.");
  const [emotionLevels, setEmotionLevels] = useState({
    curiosity: 70,
    excitement: 40,
    warmth: 50,
    playfulness: 30,
    intensity: 20,
    affection: 40,
  });
  const [fadeSpeed, setFadeSpeed] = useState(4);
  const [isPlaying, setIsPlaying] = useState(false);
  const [generatedData, setGeneratedData] = useState({ thoughts: [], output: '', totalDelay: 0 });
  const [showOutput, setShowOutput] = useState(false);

  const handleEmotionChange = useCallback((emotion, value) => {
    setEmotionLevels(prev => ({ ...prev, [emotion]: value }));
  }, []);

  const handleSimulate = useCallback(() => {
    const data = generateThoughts(input, emotionLevels);
    setGeneratedData(data);
    setIsPlaying(false);
    setShowOutput(false);
    setTimeout(() => setIsPlaying(true), 50);
    setTimeout(() => setShowOutput(true), data.totalDelay);
  }, [input, emotionLevels]);

  return (
    <div style={{
      width: '100%',
      minHeight: '100vh',
      background: COLORS.bg,
      fontFamily: 'SF Mono, Monaco, monospace',
      color: COLORS.thought,
      padding: 20,
      boxSizing: 'border-box',
    }}>
      {/* Header */}
      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 20 }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
          <div style={{
            width: 10, height: 10, borderRadius: '50%',
            background: COLORS.spoken,
            boxShadow: `0 0 10px ${COLORS.spoken}`,
            animation: isPlaying ? 'pulse 1s infinite' : 'none',
          }} />
          <span style={{ fontSize: 15, fontWeight: 600, color: '#fff' }}>Luna Thought Stream</span>
          <span style={{ fontSize: 10, color: '#555' }}>v2 — Editable</span>
        </div>
        <button
          onClick={handleSimulate}
          style={{
            padding: '10px 28px',
            background: isPlaying ? COLORS.stream : COLORS.spoken,
            border: `1px solid ${COLORS.spoken}`,
            borderRadius: 8,
            color: isPlaying ? COLORS.spoken : '#000',
            fontSize: 12,
            fontWeight: 600,
            cursor: 'pointer',
          }}
        >
          {isPlaying ? '↻ Replay' : '▶ Simulate'}
        </button>
      </div>

      <div style={{ display: 'flex', gap: 20 }}>
        {/* Left Panel */}
        <div style={{ width: 260 }}>
          {/* User Input */}
          <div style={{ marginBottom: 16 }}>
            <div style={{ fontSize: 9, color: COLORS.user, textTransform: 'uppercase', letterSpacing: 1, marginBottom: 6 }}>
              User Input
            </div>
            <textarea
              value={input}
              onChange={e => setInput(e.target.value)}
              placeholder="Type user message..."
              style={{
                width: '100%',
                minHeight: 70,
                background: COLORS.stream,
                border: `1px solid ${COLORS.user}44`,
                borderRadius: 8,
                padding: 10,
                color: COLORS.user,
                fontSize: 12,
                resize: 'vertical',
                boxSizing: 'border-box',
              }}
            />
          </div>

          {/* Emotion Controls */}
          <div style={{ marginBottom: 16 }}>
            <div style={{ fontSize: 9, color: '#555', textTransform: 'uppercase', letterSpacing: 1, marginBottom: 10 }}>
              Emotion Injection
            </div>
            {EMOTIONS.map(e => (
              <EmotionSlider key={e} emotion={e} value={emotionLevels[e]} onChange={handleEmotionChange} />
            ))}
          </div>

          {/* Fade Speed */}
          <div style={{ marginBottom: 16 }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 4 }}>
              <span style={{ fontSize: 10, color: '#666' }}>Fade Speed</span>
              <span style={{ fontSize: 10, color: '#666' }}>{fadeSpeed}s</span>
            </div>
            <input
              type="range"
              min={1}
              max={8}
              step={0.5}
              value={fadeSpeed}
              onChange={e => setFadeSpeed(parseFloat(e.target.value))}
              style={{ width: '100%' }}
            />
          </div>

          <Legend />
        </div>

        {/* Center: Stream */}
        <div style={{ flex: 1, height: 600, display: 'flex' }}>
          <ThoughtStream
            thoughts={generatedData.thoughts}
            emotionLevels={emotionLevels}
            isPlaying={isPlaying}
            fadeSpeed={fadeSpeed}
          />
        </div>

        {/* Right Panel */}
        <div style={{ width: 240 }}>
          {/* Output */}
          <div style={{
            padding: 16,
            background: `${COLORS.spoken}08`,
            border: `1px solid ${COLORS.spoken}33`,
            borderRadius: 10,
            marginBottom: 16,
            opacity: showOutput ? 1 : 0.3,
            transition: 'opacity 0.6s',
          }}>
            <div style={{ fontSize: 9, color: COLORS.spoken, textTransform: 'uppercase', letterSpacing: 1, marginBottom: 8, opacity: 0.7 }}>
              Spoken Output
            </div>
            <div style={{ fontSize: 16, color: COLORS.spoken, lineHeight: 1.5 }}>
              "{generatedData.output || '...'}"
            </div>
          </div>

          {/* Stats */}
          <div style={{ marginBottom: 16 }}>
            <div style={{ fontSize: 9, color: '#555', textTransform: 'uppercase', letterSpacing: 1, marginBottom: 8 }}>
              Processing Stats
            </div>
            <Stats thoughts={generatedData.thoughts} output={generatedData.output} />
          </div>

          {/* Compression Ratio */}
          <div style={{
            padding: 14,
            background: '#0a1a0a',
            border: '1px solid #00ff0033',
            borderRadius: 8,
            textAlign: 'center',
          }}>
            <div style={{ fontSize: 9, color: '#4ade80', textTransform: 'uppercase', marginBottom: 6 }}>
              Compression Ratio
            </div>
            <div style={{ fontSize: 28, fontWeight: 600, color: '#4ade80' }}>
              {generatedData.thoughts.length > 0 
                ? `${generatedData.thoughts.length}:${generatedData.output.split(' ').length}`
                : '—'
              }
            </div>
            <div style={{ fontSize: 9, color: '#555', marginTop: 4 }}>thoughts → words</div>
          </div>
        </div>
      </div>

      {/* Compare Footer */}
      <div style={{ marginTop: 20, display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 16 }}>
        <div style={{ padding: 14, background: '#1a0a0a', borderRadius: 10, border: '1px solid #ff000022' }}>
          <div style={{ fontSize: 9, color: '#ff6b6b', marginBottom: 6, textTransform: 'uppercase' }}>✗ Without Thought Stream</div>
          <div style={{ fontSize: 11, color: '#888', lineHeight: 1.6 }}>
            "I'm really curious about this mystery layer you've been hinting at! You mentioned it would 'tie the room together' and now I'm genuinely intrigued. What's the concept? Is it related to the prosody mapping or something else entirely?"
          </div>
        </div>
        <div style={{ padding: 14, background: '#0a1a0a', borderRadius: 10, border: '1px solid #00ff0022' }}>
          <div style={{ fontSize: 9, color: '#4ade80', marginBottom: 6, textTransform: 'uppercase' }}>✓ With Thought Stream</div>
          <div style={{ fontSize: 11, color: '#ccc', lineHeight: 1.6 }}>
            "{generatedData.output || 'What\'s the layer?'}"
          </div>
        </div>
      </div>

      <style>{`
        @keyframes fall {
          from { transform: translateY(-100%); }
          to { transform: translateY(1200%); }
        }
        @keyframes pulse {
          0%, 100% { opacity: 1; transform: scale(1); }
          50% { opacity: 0.5; transform: scale(0.95); }
        }
        @keyframes wavePulse {
          0% { opacity: 0; transform: scaleX(0); }
          30% { opacity: 1; }
          100% { opacity: 0; transform: scaleX(1); }
        }
        @keyframes emotionPulse {
          0%, 100% { transform: scale(1); opacity: 1; }
          50% { transform: scale(1.3); opacity: 0.7; }
        }
        input[type="range"] {
          -webkit-appearance: none;
          height: 4px;
          background: #1a1a28;
          border-radius: 2px;
        }
        input[type="range"]::-webkit-slider-thumb {
          -webkit-appearance: none;
          width: 14px;
          height: 14px;
          background: #8b5cf6;
          border-radius: 50%;
          cursor: pointer;
        }
        textarea:focus { outline: none; border-color: ${COLORS.user}; }
      `}</style>
    </div>
  );
}
